 43→/**
 44→ * Remove a single symlink
 45→ */
 46→function removeSymlink(symlinkPath: string): void {
 47→  try {
 48→    // Use lstatSync to detect dangling symlinks
 49→    // (existsSync follows symlinks and returns false for dangling ones)
 50→    const stat = lstatSync(symlinkPath)
 51→    if (stat.isSymbolicLink()) {
 52→      unlinkSync(symlinkPath)
