162→/**
163→ * Sync workspace projects to meta-projects symlink structure
164→ *
165→ * Creates a hierarchical symlink structure mirroring workspace categories:
166→ * ~/.config/simple-code-gui/meta-projects/
167→ * ├── Work/
168→ * │   ├── ProjectA -> /home/user/work/ProjectA
169→ * │   └── ProjectB -> /home/user/work/ProjectB
170→ * ├── Personal/
171→ * │   └── MyApp -> /home/user/Projects/MyApp
172→ * └── Uncategorized/
173→ *     └── RandomProject -> /home/user/RandomProject
174→ *
175→ * IMPORTANT: This function does incremental updates to avoid breaking
176→ * running sessions that have their cwd in a category folder. It only
177→ * removes/adds symlinks as needed rather than deleting entire directories.
178→ */
179→export function syncMetaProjects(workspace: Workspace): void {
180→  const basePath = getMetaProjectsBasePath()
181→
182→  // Ensure base directory exists
183→  if (!existsSync(basePath)) {
184→    try {
185→      mkdirSync(basePath, { recursive: true })
186→    } catch (e) {
187→      console.error('Failed to create meta-projects directory:', e)
188→      return
189→    }
190→  }
191→
192→  // Build category mapping
193→  const categoryMap = buildCategoryMap(workspace.categories)
194→
195→  // Group projects by category
196→  const projectGroups = groupProjectsByCategory(workspace.projects, categoryMap)
197→
198→  // Track which category dirs should exist
199→  const expectedCategoryDirs = new Set<string>()
200→  for (const categoryName of projectGroups.keys()) {
201→    expectedCategoryDirs.add(categoryName)
202→  }
203→
204→  // Process each category - add/update symlinks
205→  for (const [categoryName, projects] of projectGroups) {
206→    const categoryDir = join(basePath, categoryName)
207→
208→    // Create category directory if it doesn't exist
209→    if (!existsSync(categoryDir)) {
210→      try {
211→        mkdirSync(categoryDir, { recursive: true })
212→      } catch (e) {
213→        console.warn(`Failed to create category directory ${categoryDir}:`, e)
214→        continue
215→      }
216→    }
217→
218→    // Get current symlinks in this category
219→    const currentSymlinks = getCurrentSymlinks(categoryDir)
220→
221→    // Build map of what symlinks should exist (project path -> desired symlink name)
222→    const desiredSymlinks = new Map<string, string>()
223→    const usedNames = new Set<string>()
224→
225→    for (const project of projects) {
226→      const symlinkName = getUniqueSymlinkName(categoryDir, project.name, usedNames)
227→      desiredSymlinks.set(project.path, symlinkName)
228→    }
229→
230→    // Remove symlinks that shouldn't exist, point to wrong targets, or are broken
231→    for (const [name, target] of currentSymlinks) {
232→      // Check if this symlink is still needed and its target exists
233→      let shouldKeep = false
234→      for (const [projectPath, desiredName] of desiredSymlinks) {
235→        if (target === projectPath && name === desiredName) {
236→          // Also verify target still exists on disk
237→          shouldKeep = existsSync(target)
238→          break
239→        }
240→      }
241→      if (!shouldKeep) {
242→        removeSymlink(join(categoryDir, name))
243→      }
244→    }
245→
246→    // Refresh current symlinks after removals
247→    const remainingSymlinks = getCurrentSymlinks(categoryDir)
248→    const existingTargets = new Set(remainingSymlinks.values())
249→
250→    // Create new symlinks that don't exist yet
251→    for (const [projectPath, symlinkName] of desiredSymlinks) {
252→      if (!existingTargets.has(projectPath)) {
253→        createSymlink(projectPath, join(categoryDir, symlinkName))
254→      }
255→    }
256→  }
257→
258→  // Remove category directories that shouldn't exist anymore
259→  // But only remove symlinks inside, keep the directory if it still has content
260→  try {
261→    const existingDirs = readdirSync(basePath)
262→    for (const dirName of existingDirs) {
263→      if (!expectedCategoryDirs.has(dirName)) {
264→        const dirPath = join(basePath, dirName)
265→        const stat = lstatSync(dirPath)
266→        if (stat.isDirectory() && !stat.isSymbolicLink()) {
267→          // Remove all symlinks in this directory
268→          const symlinks = getCurrentSymlinks(dirPath)
269→          for (const name of symlinks.keys()) {
270→            removeSymlink(join(dirPath, name))
271→          }
272→          // Try to remove directory if empty
273→          removeEmptyCategoryDir(dirPath)
274→        }
275→      }
276→    }
277→  } catch (e) {
278→    console.warn('Failed to clean up old category directories:', e)
279→  }
280→}
