    10→ */
    11→function getMetaProjectsBasePath(): string {
    12→  return join(app.getPath('userData'), 'meta-projects')
    13→}
    14→
    15→/**
    16→ * Get current symlinks in a category directory
    17→ * Returns map of symlink name -> target path
    18→ */
    19→function getCurrentSymlinks(categoryDir: string): Map<string, string> {
    20→  const symlinks = new Map<string, string>()
    21→  if (!existsSync(categoryDir)) return symlinks
    22→
    23→  try {
    24→    const entries = readdirSync(categoryDir)
    25→    for (const entry of entries) {
    26→      const entryPath = join(categoryDir, entry)
    27→      try {
    28→        const stat = lstatSync(entryPath)
    29→        if (stat.isSymbolicLink()) {
    30→          const target = readlinkSync(entryPath)
    31→          symlinks.set(entry, target)
    32→        }
    33→      } catch {
    34→        // Skip entries we can't stat
    35→      }
    36→    }
    37→  } catch {
    38→    // Directory might not exist or be readable
    39→  }
    40→  return symlinks
    41→}
    42→
    43→/**
    44→ * Remove a single symlink
    45→ */
    46→function removeSymlink(symlinkPath: string): void {
    47→  try {
    48→    // Use lstatSync to detect dangling symlinks
    49→    // (existsSync follows symlinks and returns false for dangling ones)
    50→    const stat = lstatSync(symlinkPath)
    51→    if (stat.isSymbolicLink()) {
    52→      unlinkSync(symlinkPath)
    53→    }
    54→  } catch (e: any) {
    55→    if (e?.code !== "ENOENT") {
    56→      console.warn(`Failed to remove symlink ${symlinkPath}:`, e)
    57→    }
    58→  }
    59→}
    60→
    61→/**
    62→ * Remove an empty category directory (only if it's empty)
    63→ */
    64→function removeEmptyCategoryDir(categoryDir: string): void {
    65→  if (!existsSync(categoryDir)) return
    66→
    67→  try {
    68→    const entries = readdirSync(categoryDir)
    69→    if (entries.length === 0) {
    70→      rmSync(categoryDir, { recursive: true, force: true })
    71→    }
    72→  } catch (e) {
    73→    console.warn(`Failed to remove empty category dir ${categoryDir}:`, e)
    74→  }
    75→}
    76→
    77→/**
    78→ * Generate a unique symlink name by appending numbers if needed
    79→ */
    80→function getUniqueSymlinkName(dir: string, baseName: string, existingNames: Set<string>): string {
    81→  // Sanitize name for filesystem
    82→  let name = baseName.replace(/[/\\:*?"<>|]/g, '_')
    83→
    84→  if (!existingNames.has(name)) {
    85→    existingNames.add(name)
    86→    return name
    87→  }
    88→
    89→  // Append numbers until unique
    90→  let counter = 2
    91→  while (existingNames.has(`${name}-${counter}`)) {
    92→    counter++
    93→  }
    94→
    95→  const uniqueName = `${name}-${counter}`
    96→  existingNames.add(uniqueName)
    97→  return uniqueName
    98→}
