    75→        console.error('[Orchestrator] API server error:', e.message)
    76→        this.server?.close()
    77→        this.server = null
    78→      }
    79→    })
    80→  }
    81→
    82→  stop(): void {
    83→    this.server?.close()
    84→    this.server = null
    85→  }
    86→
    87→  private handleListSessions(res: http.ServerResponse): void {
    88→    const sessions = this.ptyManager.listSessions()
    89→    // Enrich with project path from ptyToProject map
