    95→    res.writeHead(200)
    96→    res.end(JSON.stringify({ sessions: enriched }))
    97→  }
    98→
    99→  private handleReadOutput(id: string, maxLines: number, res: http.ServerResponse): void {
   100→    const lines = this.ptyManager.readOutput(id, maxLines)
   101→    if (lines === null) {
   102→      res.writeHead(404)
   103→      res.end(JSON.stringify({ error: 'Session not found' }))
   104→      return
   105→    }
   106→    res.writeHead(200)
   107→    res.end(JSON.stringify({ lines }))
   108→  }
   109→
   110→  private handleSendInput(id: string, req: http.IncomingMessage, res: http.ServerResponse): void {
   111→    let body = ''
   112→    req.on('data', chunk => {
   113→      body += chunk
   114→      if (body.length > 10240) {
