   116→        res.end(JSON.stringify({ error: 'Input too large' }))
   117→        req.destroy()
   118→      }
   119→    })
   120→    req.on('end', () => {
   121→      try {
   122→        const data = JSON.parse(body)
   123→        const input = data.input || data.text || data.message || ''
   124→        if (!input) {
