   239→export function setupIpAccessMiddleware(app: Express): void {
   240→  app.use((req: Request, res: Response, next: NextFunction) => {
   241→    // Skip for unauthenticated endpoints and static files
   242→    if (req.path === '/health' || req.path === '/connect' || req.path === '/verify-handshake' || req.path === '/ws-test') {
   243→      return next()
   244→    }
   245→    if (isStaticPath(req.path)) {
   246→      return next()
   247→    }
   248→
   249→    const clientIp = getClientIp(req)
   250→    const ipClass = classifyIp(clientIp)
   251→
   252→    // Determine required access level for this endpoint
   253→    const accessLevel = getEndpointAccessLevel(req.path, req.method)
   254→
   255→    // Check if IP class is allowed for this access level
   256→    if (!isAccessAllowed(ipClass, accessLevel)) {
   257→      return res.status(403).json({
