275→  ipcMain.handle('kspec:init', async (_event, cwd: string) => {
276→    try {
277→      // Check if it's a git repo first
278→      const gitDir = join(cwd, '.git')
279→      if (!existsSync(gitDir)) {
280→        // Init git first
281→        const gitResult = await spawnCommand('git', ['init'], cwd)
282→        if (gitResult.code !== 0) {
283→          return { success: false, error: `Failed to init git: ${gitResult.stderr}` }
284→        }
285→        // Set default git config for the repo
286→        await spawnCommand('git', ['config', 'user.name', 'kspec'], cwd)
287→        await spawnCommand('git', ['config', 'user.email', 'kspec@local'], cwd)
288→        await spawnCommand('git', ['commit', '--allow-empty', '-m', 'init'], cwd)
289→      }
290→
291→      // Run kspec init
