295→      }
296→
297→      // Run kspec setup — sets up agent definitions, skills, .agents/ directory
298→      await spawnCommand('kspec', ['setup'], cwd)
299→
300→      // Generate kspec-agents.md — full agent instructions with workflows, conventions, skills
301→      await spawnCommand('kspec', ['agents', 'generate'], cwd)
302→
303→      // Add task instructions to CLAUDE.md pointing at kspec-agents.md
304→      installTaskInstructions(cwd, 'kspec')
305→
306→      return { success: true }
307→    } catch (e) {
308→      return { success: false, error: String(e) }
309→    }
310→  })
311→
312→  // Start kspec daemon if not running
313→  let updateCheckDone = false
314→  ipcMain.handle('kspec:ensure-daemon', async (_event, cwd: string) => {
315→    try {
316→      // Check if daemon is already running
317→      const res = await fetch('http://localhost:3456/api/health').catch(() => null)
318→      if (res?.ok) {
319→        // Register this project with the running daemon
320→        await fetch('http://localhost:3456/api/projects', {
321→          method: 'POST',
322→          headers: { 'Content-Type': 'application/json' },
323→          body: JSON.stringify({ path: cwd })
324→        }).catch(() => {})
325→
326→        // Background update check (once per app session, non-blocking)
327→        if (!updateCheckDone) {
328→          updateCheckDone = true
329→          checkAndUpdateKspec().catch(() => {})
330→        }
331→
332→        return { success: true, alreadyRunning: true }
333→      }
334→
335→      // Start daemon in background
336→      const proc = spawn('kspec', ['serve', 'start', '--daemon'], {
337→        cwd,
338→        env: getExecOptions().env,
339→        detached: true,
340→        stdio: 'ignore'
341→      })
342→      proc.unref()
343→
344→      // Wait for daemon to be ready (up to 5 seconds)
345→      for (let i = 0; i < 10; i++) {
346→        await new Promise(r => setTimeout(r, 500))
347→        const check = await fetch('http://localhost:3456/api/health').catch(() => null)
348→        if (check?.ok) {
349→          return { success: true, alreadyRunning: false }
350→        }
351→      }
352→
353→      return { success: false, error: 'Daemon did not start in time' }
354→    } catch (e) {
355→      return { success: false, error: String(e) }
356→    }
357→  })
358→
359→  // Check if kspec CLI is installed
360→  ipcMain.handle('kspec:check-cli', async () => {
361→    try {
362→      const result = await spawnCommand('kspec', ['--version'], process.cwd())
363→      return { installed: result.code === 0, version: result.stdout.trim() }
364→    } catch {
365→      return { installed: false }
366→    }
367→  })
368→
369→  // Install kspec CLI via npm
370→  ipcMain.handle('kspec:install-cli', async () => {
371→    try {
372→      const result = await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec'], process.cwd())
373→      if (result.code !== 0) {
374→        return { success: false, error: result.stderr || 'npm install failed' }
375→      }
376→      return { success: true }
377→    } catch (e) {
378→      return { success: false, error: String(e) }
379→    }
380→  })
381→
382→  // Migrate beads tasks to kspec (upgrade path)
383→  ipcMain.handle('kspec:migrate-from-beads', async (_event, cwd: string) => {
384→    return migrateBeadsToKspec(cwd)
385→  })
386→
387→  // Check for kspec updates and install if available
388→  ipcMain.handle('kspec:update', async () => {
389→    try {
390→      // Get installed version
391→      const localResult = await spawnCommand('kspec', ['--version'], process.cwd())
392→      if (localResult.code !== 0) return { updated: false, error: 'kspec not installed' }
393→      const localVersion = localResult.stdout.trim().replace(/^v/, '')
394→
395→      // Get latest version from npm
396→      const npmResult = await spawnCommand('npm', ['view', '@kynetic-ai/spec', 'version'], process.cwd())
397→      if (npmResult.code !== 0) return { updated: false, error: 'Could not check npm' }
398→      const latestVersion = npmResult.stdout.trim()
399→
400→      if (localVersion === latestVersion) {
401→        return { updated: false, current: localVersion, latest: latestVersion }
402→      }
403→
404→      // Update
405→      const updateResult = await spawnCommand('npm', ['install', '-g', '@kynetic-ai/spec@latest'], process.cwd())
406→      if (updateResult.code !== 0) {
407→        return { updated: false, error: updateResult.stderr || 'Update failed', current: localVersion, latest: latestVersion }
408→      }
409→
410→      return { updated: true, previous: localVersion, current: latestVersion }
411→    } catch (e) {
412→      return { updated: false, error: String(e) }
413→    }
414→  })
415→
416→  // Start agent dispatch
417→  ipcMain.handle('kspec:dispatch-start', async (_event, cwd: string) => {
418→    try {
419→      const result = await spawnCommand('kspec', ['agent', 'dispatch', 'start'], cwd)
420→      if (result.code !== 0) {
421→        return { success: false, error: result.stderr || 'Failed to start dispatch' }
422→      }
423→      return { success: true }
424→    } catch (e) {
425→      return { success: false, error: String(e) }
426→    }
