import { BrowserWindow, dialog, ipcMain } from 'electron'
import { join } from 'path'
import { readdirSync, statSync } from 'fs'
import { SessionStore } from '../../session-store.js'
import { getMetaProjectsPath } from '../../meta-project-sync.js'
import { discoverSessions } from '../../session-discovery.js'

export function registerWorkspaceHandlers(
  sessionStore: SessionStore,
  getMainWindow: () => BrowserWindow | null
): void {
  ipcMain.handle('workspace:get', () => sessionStore.getWorkspace())
  ipcMain.handle('workspace:save', (_, workspace) => sessionStore.saveWorkspace(workspace))
  ipcMain.handle('workspace:getMetaProjectsPath', () => getMetaProjectsPath())
  ipcMain.handle('workspace:getCategoryMetaPath', (_, categoryName: string) => {
    const basePath = getMetaProjectsPath()
    // Sanitize category name for filesystem
    const safeName = categoryName.replace(/[/\\:*?"<>|]/g, '_')
    return join(basePath, safeName)
  })
  ipcMain.handle('workspace:addProject', async () => {
    const mainWindow = getMainWindow()
    const result = await dialog.showOpenDialog(mainWindow!, {
      properties: ['openDirectory'],
      title: 'Select Project Folder'
    })
    return result.canceled ? null : result.filePaths[0] || null
  })

  ipcMain.handle('workspace:addProjectsFromParent', async () => {
    const mainWindow = getMainWindow()
    const result = await dialog.showOpenDialog(mainWindow!, {
      properties: ['openDirectory'],
      title: 'Select Parent Folder (all subdirectories will be added as projects)'
    })
    if (result.canceled || !result.filePaths[0]) return null

    const parentDir = result.filePaths[0]

    try {
      const entries = readdirSync(parentDir, { withFileTypes: true })
      const subdirs = entries
        .filter((entry) => entry.isDirectory() && !entry.name.startsWith('.'))
        .map((entry) => ({
          path: join(parentDir, entry.name),
          name: entry.name
        }))
      return subdirs
    } catch (e) {
      console.error('Failed to scan parent directory:', e)
      return null
    }
  })

  // Session discovery
  ipcMain.handle('sessions:discover', (_, projectPath: string, backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => discoverSessions(projectPath, backend))
}

/**
 * Project Routes - Workspace
 *
 * HTTP endpoints for workspace and project list management.
 */

import { Router, Request, Response } from 'express'
import { Workspace } from '../../types.js'
import { getServices } from '../../app.js'
import { sendResponse, sendError } from './helpers.js'

const router = Router()

/**
 * GET /api/projects
 * Get the full workspace including all projects
 *
 * Returns: Workspace
 */
router.get('/', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = await services.getWorkspace()

    sendResponse(res, 200, {
      success: true,
      data: workspace,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Projects Route] Get workspace error:', error)
    sendError(res, 500, error.message || 'Failed to get workspace')
  }
})

/**
 * PUT /api/projects
 * Save the full workspace
 *
 * Body: Workspace
 */
router.put('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.saveWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = req.body

    if (!workspace || !Array.isArray(workspace.projects)) {
      return sendError(res, 400, 'Invalid workspace data')
    }

    await services.saveWorkspace(workspace)

    sendResponse(res, 200, {
      success: true,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Projects Route] Save workspace error:', error)
    sendError(res, 500, error.message || 'Failed to save workspace')
  }
})

/**
 * GET /api/projects/list
 * Get just the list of projects (convenience endpoint)
 *
 * Returns: Project[]
 */
router.get('/list', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getWorkspace) {
      return sendError(res, 503, 'Workspace service not available')
    }

    const workspace: Workspace = await services.getWorkspace()

    sendResponse(res, 200, {
      success: true,
      data: workspace.projects,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to get projects')
  }
})

export default router

/**
 * Mobile API Server - Express Application
 *
 * Main server setup that exposes desktop IPC functionality as HTTP/WebSocket endpoints.
 * Enables mobile app communication with the Claude Terminal desktop application.
 */

import express, { Express, Request, Response, NextFunction } from 'express'
import * as http from 'http'
import cors from 'cors'
import {
  MobileApiServerConfig,
  DEFAULT_SERVER_CONFIG,
  ApiResponse
} from './types'
import {
  authMiddleware,
  generatePrimaryToken,
  getPrimaryToken,
  getConnectionInfo,
  cleanupExpiredTokens
} from './auth'
import { createApiRouter } from './routes'
import { WebSocketHandler } from './ws-handler'

// =============================================================================
// Server State
// =============================================================================

let serverInstance: http.Server | null = null
let wsHandler: WebSocketHandler | null = null
let cleanupInterval: NodeJS.Timeout | null = null

// =============================================================================
// Service Registrations (IPC Handler Adapters)
// =============================================================================

/**
 * Service interfaces that bridge IPC handlers to HTTP endpoints
 * These are set by the main process to provide access to existing functionality
 */
export interface ServerServices {
  // Workspace/Project management
  getWorkspace: () => Promise<any>
  saveWorkspace: (workspace: any) => Promise<void>

  // Settings
  getSettings: () => Promise<any>
  saveSettings: (settings: any) => Promise<void>

  // Sessions
  discoverSessions: (projectPath: string, backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => Promise<any[]>

  // PTY management
  spawnPty: (cwd: string, sessionId?: string, model?: string, backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => Promise<string>
  writePty: (id: string, data: string) => void
  resizePty: (id: string, cols: number, rows: number) => void
  killPty: (id: string) => void
  onPtyData: (id: string, callback: (data: string) => void) => () => void
  onPtyExit: (id: string, callback: (code: number) => void) => () => void

  // Beads task management
  beadsCheck: (cwd: string) => Promise<any>
  beadsInit: (cwd: string) => Promise<any>
  beadsList: (cwd: string) => Promise<any>
  beadsShow: (cwd: string, taskId: string) => Promise<any>
  beadsCreate: (cwd: string, title: string, description?: string, priority?: number, type?: string, labels?: string) => Promise<any>
  beadsComplete: (cwd: string, taskId: string) => Promise<any>
  beadsDelete: (cwd: string, taskId: string) => Promise<any>
  beadsStart: (cwd: string, taskId: string) => Promise<any>
  beadsUpdate: (cwd: string, taskId: string, status?: string, title?: string, description?: string, priority?: number) => Promise<any>

  // GSD progress
  gsdProjectCheck: (cwd: string) => Promise<any>
  gsdGetProgress: (cwd: string) => Promise<any>

  // Voice (TTS)
  voiceSpeak: (text: string) => Promise<any>
  voiceStopSpeaking: () => Promise<any>
  voiceGetSettings: () => Promise<any>

  // CLI checks
  claudeCheck: () => Promise<any>
  geminiCheck: () => Promise<any>
  codexCheck: () => Promise<any>
  opencodeCheck: () => Promise<any>
  aiderCheck: () => Promise<any>
}

let services: Partial<ServerServices> = {}

/**
 * Register services that provide IPC handler functionality
 */
export function registerServices(newServices: Partial<ServerServices>): void {
  services = { ...services, ...newServices }
}

/**
 * Get registered services
 */
export function getServices(): Partial<ServerServices> {
  return services
}

// =============================================================================
// Express App Factory
// =============================================================================

/**
 * Create and configure the Express application
 */
export function createApp(config: MobileApiServerConfig = DEFAULT_SERVER_CONFIG): Express {
  const app = express()

  // ==========================================================================
  // Middleware Stack
  // ==========================================================================

  // JSON body parsing with size limit
  app.use(express.json({ limit: '100kb' }))

  // CORS configuration
  if (config.enableCors) {
    app.use(cors({
      origin: config.corsOrigins || '*',
      methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS'],
      allowedHeaders: ['Content-Type', 'Authorization'],
      credentials: true
    }))
  }

  // Request logging (development)
  app.use((req: Request, _res: Response, next: NextFunction) => {
    console.log(`[Mobile API] ${req.method} ${req.path}`)
    next()
  })

  // ==========================================================================
  // Health Check (unauthenticated)
  // ==========================================================================

  app.get('/health', (_req: Request, res: Response) => {
    const response: ApiResponse<{ status: string; uptime: number }> = {
      success: true,
      data: {
        status: 'healthy',
        uptime: process.uptime()
      },
      timestamp: Date.now()
    }
    res.json(response)
  })

  // ==========================================================================
  // Connection Info (unauthenticated - for initial pairing)
  // ==========================================================================

  app.get('/connect', (_req: Request, res: Response) => {
    const token = getPrimaryToken()
    if (!token) {
      res.status(503).json({
        success: false,
        error: 'Server not fully initialized',
        timestamp: Date.now()
      })
      return
    }

    // Return connection info for QR code
    const info = getConnectionInfo(config.host, config.port)
    res.json({
      success: true,
      data: {
        version: 1,
        wsEndpoint: `/ws`,
        apiEndpoint: `/api`,
        tokenHint: info.token.slice(0, 8) + '...' // Partial token for verification
      },
      timestamp: Date.now()
    })
  })

  // ==========================================================================
  // API Routes (authenticated)
  // ==========================================================================

  // Apply auth middleware to all /api routes
  app.use('/api', authMiddleware as any)

  // Mount the API router
  app.use('/api', createApiRouter())

  // ==========================================================================
  // Error Handling
  // ==========================================================================

  // 404 handler
  app.use((_req: Request, res: Response) => {
    res.status(404).json({
      success: false,
      error: 'Endpoint not found',
      timestamp: Date.now()
    })
  })

  // Global error handler
  app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
    console.error('[Mobile API] Error:', err)
    res.status(500).json({
      success: false,
      error: process.env.NODE_ENV === 'development' ? err.message : 'Internal server error',
      timestamp: Date.now()
    })
  })

  return app
}

// =============================================================================
// Server Lifecycle
// =============================================================================

/**
 * Start the mobile API server
 */
export function startServer(
  config: Partial<MobileApiServerConfig> = {}
): Promise<{ server: http.Server; wsHandler: WebSocketHandler; token: string }> {
  return new Promise((resolve, reject) => {
    const fullConfig: MobileApiServerConfig = { ...DEFAULT_SERVER_CONFIG, ...config }

    // Stop existing server if running
    if (serverInstance) {
      stopServer()
    }

    // Generate primary auth token
    const token = generatePrimaryToken()
    console.log('[Mobile API] Generated auth token:', token.token.slice(0, 8) + '...')

    // Create Express app
    const app = createApp(fullConfig)

    // Create HTTP server
    serverInstance = http.createServer(app)

    // Set up WebSocket handler if enabled
    if (fullConfig.enableWebSocket) {
      wsHandler = new WebSocketHandler(serverInstance, fullConfig.maxConnections)
    }

    // Start periodic cleanup of expired tokens
    cleanupInterval = setInterval(() => {
      const cleaned = cleanupExpiredTokens()
      if (cleaned > 0) {
        console.log(`[Mobile API] Cleaned up ${cleaned} expired tokens`)
      }
    }, 60000) // Every minute

    // Start listening
    serverInstance.listen(fullConfig.port, fullConfig.host, () => {
      console.log(`[Mobile API] Server started on ${fullConfig.host}:${fullConfig.port}`)
      console.log(`[Mobile API] WebSocket endpoint: ws://${fullConfig.host}:${fullConfig.port}/ws`)

      resolve({
        server: serverInstance!,
        wsHandler: wsHandler!,
        token: token.token
      })
    })

    serverInstance.on('error', (error: NodeJS.ErrnoException) => {
      console.error('[Mobile API] Server error:', error)
      if (error.code === 'EADDRINUSE') {
        reject(new Error(`Port ${fullConfig.port} is already in use`))
      } else {
        reject(error)
      }
    })
  })
}

/**
 * Stop the mobile API server
 */
export function stopServer(): Promise<void> {
  return new Promise((resolve) => {
    // Stop cleanup interval
    if (cleanupInterval) {
      clearInterval(cleanupInterval)
      cleanupInterval = null
    }

    // Close WebSocket handler
    if (wsHandler) {
      wsHandler.closeAll()
      wsHandler = null
    }

    // Close HTTP server
    if (serverInstance) {
      serverInstance.close(() => {
        console.log('[Mobile API] Server stopped')
        serverInstance = null
        resolve()
      })
    } else {
      resolve()
    }
  })
}

/**
 * Check if server is running
 */
export function isServerRunning(): boolean {
  return serverInstance !== null && serverInstance.listening
}

/**
 * Get the WebSocket handler instance
 */
export function getWsHandler(): WebSocketHandler | null {
  return wsHandler
}

/**
 * Get server information
 */
export function getServerInfo(): {
  running: boolean
  port?: number
  host?: string
  token?: string
  connections?: number
} {
  if (!serverInstance || !serverInstance.listening) {
    return { running: false }
  }

  const address = serverInstance.address()
  const token = getPrimaryToken()

  return {
    running: true,
    port: typeof address === 'object' && address ? address.port : undefined,
    host: typeof address === 'object' && address ? address.address : undefined,
    token: token?.token,
    connections: wsHandler?.getConnectionCount() ?? 0
  }
}

import { app, BrowserWindow } from 'electron'
import { join } from 'path'
import { mkdirSync, existsSync, copyFileSync, statSync } from 'fs'

import { PtyManager } from './pty-manager.js'
import { SessionStore } from './session-store.js'
import { ApiServerManager } from './api-server.js'
import { OrchestratorApi } from './orchestrator-api.js'
import { MobileServer } from './mobile-server.js'
import { voiceManager } from './voice-manager.js'
import { setPortableBinDirs } from './platform.js'
import { getPortableBinDirs } from './portable-deps.js'
import { initUpdater } from './updater.js'
import {
  registerCliHandlers,
  registerBeadsHandlers,
  registerVoiceHandlers,
  registerExtensionHandlers,
  registerWindowHandlers,
  registerGsdHandlers,
  registerKspecHandlers,
} from './ipc/index.js'

import { setupAppConfig, setupSecurityHeaders } from './app/app-setup.js'
import { createApplicationMenu } from './app/menu.js'
import { createWindow } from './app/window.js'
import { setupApiPromptHandler } from './app/api-prompt-handler.js'
import { registerWorkspaceHandlers } from './app/ipc-handlers/workspace.js'
import { registerPtyHandlers } from './app/ipc-handlers/pty.js'
import { registerServerHandlers } from './app/ipc-handlers/servers.js'
import { registerSettingsHandlers } from './app/ipc-handlers/settings.js'

// Apply app config (must be done before app.whenReady)
setupAppConfig()

// Single instance lock
const gotTheLock = app.requestSingleInstanceLock()
if (!gotTheLock) {
  app.quit()
} else {
  app.on('second-instance', () => {
    if (mainWindow) {
      if (mainWindow.isMinimized()) mainWindow.restore()
      mainWindow.focus()
    }
  })
}

let mainWindow: BrowserWindow | null = null
const ptyManager = new PtyManager()
const sessionStore = new SessionStore()
const apiServerManager = new ApiServerManager()
const mobileServer = new MobileServer()

// PTY tracking
const ptyToProject = new Map<string, string>()
const ptyToBackend = new Map<string, string>()

const orchestratorApi = new OrchestratorApi(ptyManager, ptyToProject)

const getMainWindow = (): BrowserWindow | null => mainWindow
const setMainWindow = (win: BrowserWindow | null): void => { mainWindow = win }

// Register IPC handlers
registerCliHandlers(getMainWindow)
registerBeadsHandlers(getMainWindow)
registerVoiceHandlers(getMainWindow)
registerExtensionHandlers()
registerWindowHandlers(getMainWindow)
registerGsdHandlers()
registerKspecHandlers()
registerWorkspaceHandlers(sessionStore, getMainWindow)
registerPtyHandlers(ptyManager, sessionStore, apiServerManager, ptyToProject, ptyToBackend, getMainWindow)
registerServerHandlers(apiServerManager, mobileServer)
registerSettingsHandlers(sessionStore, getMainWindow)

// Setup API prompt handler
setupApiPromptHandler(apiServerManager, sessionStore, ptyManager, ptyToProject, getMainWindow)

app.whenReady().then(() => {
  // Migrate data from old app name
  const oldConfigDir = join(app.getPath('appData'), 'simple-claude-gui', 'config')
  const newConfigDir = join(app.getPath('userData'), 'config')
  const oldWorkspace = join(oldConfigDir, 'workspace.json')
  const newWorkspace = join(newConfigDir, 'workspace.json')

  if (existsSync(oldWorkspace)) {
    try {
      const oldSize = statSync(oldWorkspace).size
      let shouldMigrate = false

      if (!existsSync(newWorkspace)) {
        shouldMigrate = true
      } else {
        const newSize = statSync(newWorkspace).size
        if (oldSize > 500 && newSize < 500) shouldMigrate = true
      }

      if (shouldMigrate) {
        console.log('Migrating workspace from simple-claude-gui to simple-code-gui...')
        mkdirSync(newConfigDir, { recursive: true })
        copyFileSync(oldWorkspace, newWorkspace)

        const oldVoice = join(app.getPath('appData'), 'simple-claude-gui', 'voice-settings.json')
        const newVoice = join(app.getPath('userData'), 'voice-settings.json')
        if (existsSync(oldVoice) && !existsSync(newVoice)) {
          copyFileSync(oldVoice, newVoice)
        }
        console.log('Migration complete')
      }
    } catch (err) {
      console.error('Workspace migration failed, continuing with empty workspace:', err)
    }
  }

  // Initialize portable deps PATH
  const portableDirs = getPortableBinDirs()
  setPortableBinDirs(portableDirs)

  // Setup security headers
  setupSecurityHeaders()

  createApplicationMenu(mainWindow)
  mainWindow = createWindow(sessionStore, ptyManager, setMainWindow)
  createApplicationMenu(mainWindow)
  if (mainWindow) initUpdater(mainWindow)

  // Start orchestrator API for MCP-based session control
  orchestratorApi.start()

  // Start mobile server for phone app connectivity
  mobileServer.setPtyManager(ptyManager)
  mobileServer.setSessionStore(sessionStore)
  mobileServer.setVoiceManager(voiceManager)
  mobileServer.start().then(() => {
    const info = mobileServer.getConnectionInfo()
    console.log(`[Mobile] Server ready at ${info.ips[0]}:${info.port}`)
  }).catch(err => {
    console.error('[Mobile] Failed to start server:', err)
  })

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      mainWindow = createWindow(sessionStore, ptyManager, setMainWindow)
      createApplicationMenu(mainWindow)
    }
  })
})

