/**
 * PTY Routes - /api/pty/* endpoints
 */

import { Express, Request, Response } from 'express'
import { WebSocket } from 'ws'
import { validateProjectPath } from '../../mobile-security'
import { log } from '../utils'
import { LocalPty } from '../types'

export function setupPtyRoutes(
  app: Express,
  getPtyManager: () => any,
  getLocalPtys: () => Map<string, LocalPty>,
  getPtyStreams: () => Map<string, Set<WebSocket>>,
  getPtyDataBuffer: () => Map<string, string[]>,
  broadcastPtyData: (ptyId: string, data: string) => void,
  broadcastPtyExit: (ptyId: string, code: number) => void
): void {
  // Spawn a new PTY
  app.post('/api/pty/spawn', async (req: Request, res: Response) => {
    try {
      const { projectPath, sessionId, model, backend } = req.body

      if (!projectPath || typeof projectPath !== 'string') {
        return res.status(400).json({ error: 'projectPath is required' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      log('PTY spawn request', { projectPath: safeProjectPath, sessionId, model, backend })

      const ptyId = ptyManager.spawn(
        safeProjectPath,
        sessionId,
        undefined, // autoAcceptTools
        undefined, // permissionMode
        model,
        backend
      )

      // Track this PTY for cleanup
      const localPty: LocalPty = {
        ptyId,
        projectPath: safeProjectPath,
        dataCallbacks: new Set(),
        exitCallbacks: new Set()
      }
      getLocalPtys().set(ptyId, localPty)

      // Set up data forwarding to WebSocket streams
      ptyManager.onData(ptyId, (data: string) => {
        broadcastPtyData(ptyId, data)
      })

      // Set up exit handler
      ptyManager.onExit(ptyId, (code: number) => {
        log('PTY exited', { ptyId, code })
        broadcastPtyExit(ptyId, code)
        getLocalPtys().delete(ptyId)
        getPtyStreams().delete(ptyId)
        getPtyDataBuffer().delete(ptyId)
      })

      log('PTY spawned', { ptyId, projectPath })
      res.json({ ptyId })
    } catch (error) {
      log('PTY spawn error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Write data to PTY
  app.post('/api/pty/:id/write', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { data } = req.body

      if (!data || typeof data !== 'string') {
        return res.status(400).json({ error: 'data is required and must be a string' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.write(id, data)
      log('PTY write', { ptyId: id, dataLength: data.length })
      res.json({ success: true })
    } catch (error) {
      log('PTY write error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Resize PTY
  app.post('/api/pty/:id/resize', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { cols, rows } = req.body

      if (typeof cols !== 'number' || typeof rows !== 'number') {
        return res.status(400).json({ error: 'cols and rows are required and must be numbers' })
      }

      if (cols < 1 || rows < 1 || cols > 500 || rows > 500) {
        return res.status(400).json({ error: 'cols and rows must be between 1 and 500' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.resize(id, cols, rows)
      log('PTY resize', { ptyId: id, cols, rows })
      res.json({ success: true })
    } catch (error) {
      log('PTY resize error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Kill PTY
  app.delete('/api/pty/:id', (req: Request, res: Response) => {
    try {
      const { id } = req.params

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.kill(id)
      getLocalPtys().delete(id)

      // Close any WebSocket streams for this PTY
      const streams = getPtyStreams().get(id)
      if (streams) {
        streams.forEach(ws => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.close(1000, 'PTY killed')
          }
        })
        getPtyStreams().delete(id)
      }

      log('PTY killed', { ptyId: id })
      res.json({ success: true })
    } catch (error) {
      log('PTY kill error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })
}

import * as pty from 'node-pty'
import * as fs from 'fs'
import * as path from 'path'
import {
  isWindows,
  getEnhancedPathWithPortable,
  getAdditionalPaths,
} from './platform'
import { getPortableBinDirs } from './portable-deps'

// Backends that use Ink (React for CLI) and are sensitive to rapid resize during startup
const INK_BACKENDS = new Set(['gemini'])

// Ring buffer for storing recent PTY output
const OUTPUT_BUFFER_MAX_LINES = 200

class OutputBuffer {
  private lines: string[] = []
  private partial: string = '' // incomplete line (no newline yet)

  append(data: string): void {
    // Split incoming data by newlines, preserving partial lines
    const text = this.partial + data
    const parts = text.split('\n')
    // Last element is either empty (if data ended with \n) or a partial line
    this.partial = parts.pop() || ''
    for (const line of parts) {
      // Strip ANSI escape sequences for readability
      const clean = line.replace(/\x1b\[[0-9;]*[a-zA-Z]/g, '').replace(/\x1b\][^\x07]*\x07/g, '').trim()
      if (clean) {
        this.lines.push(clean)
        if (this.lines.length > OUTPUT_BUFFER_MAX_LINES) {
          this.lines.shift()
        }
      }
    }
  }

  getRecent(maxLines: number = 50): string[] {
    return this.lines.slice(-maxLines)
  }

  clear(): void {
    this.lines = []
    this.partial = ''
  }
}

interface ClaudeProcess {
  id: string
  pty: pty.IPty
  cwd: string
  sessionId?: string
  backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
  disposables: { dispose: () => void }[]
  spawnedAt: number
  resizeTimeout?: ReturnType<typeof setTimeout>
  lastResizeCols?: number
  lastResizeRows?: number
  outputBuffer: OutputBuffer
}

// Extended node-pty options - useConpty is a Windows-specific option not in @types/node-pty
interface ExtendedPtyForkOptions extends pty.IPtyForkOptions {
  useConpty?: boolean
}

function getEnhancedEnv(): { [key: string]: string } {
  const env = { ...process.env } as { [key: string]: string }
  delete env.CLAUDECODE
  const enhancedPath = getEnhancedPathWithPortable()

  // On Windows, environment variables are case-insensitive but we need to set the right one
  if (isWindows) {
    // Windows uses 'Path' but Node sometimes uses 'PATH' - set both to be safe
    env.PATH = enhancedPath
    env.Path = enhancedPath

    // Claude Code on Windows requires git-bash - try to find and set it
    if (!env.CLAUDE_CODE_GIT_BASH_PATH) {
      const gitBashPaths = [
        'C:\\Program Files\\Git\\bin\\bash.exe',
        'C:\\Program Files (x86)\\Git\\bin\\bash.exe',
        path.join(
          process.env.LOCALAPPDATA || '',
          'Programs',
          'Git',
          'bin',
          'bash.exe'
        ),
        path.join(process.env.PROGRAMFILES || '', 'Git', 'bin', 'bash.exe'),
      ]
      for (const bashPath of gitBashPaths) {
        if (fs.existsSync(bashPath)) {
          env.CLAUDE_CODE_GIT_BASH_PATH = bashPath
          console.log('Found git-bash at:', bashPath)
          break
        }
      }
    }
  } else {
    env.PATH = enhancedPath
  }

  console.log('Enhanced PATH for PTY:', enhancedPath.substring(0, 200) + '...')
  return env
}

// Find executable for the given backend
function findExecutable(
  backend: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider' = 'claude'
): string {
  if (backend === 'gemini') {
    return findGeminiExecutable()
  }
  if (backend === 'codex') {
    return findCodexExecutable()
  }
  if (backend === 'opencode') {
    return findOpenCodeExecutable()
  }
  if (backend === 'aider') {
    return findAiderExecutable()
  }
  return findClaudeExecutable()
}

// Find gemini executable - on Windows, npm installs .cmd files
function findGeminiExecutable(): string {
  if (!isWindows) {
    return 'gemini'
  }

  // On Windows, check for gemini.cmd in portable npm-global first
  const portableDirs = getPortableBinDirs()
  for (const dir of portableDirs) {
    const geminiCmd = path.join(dir, 'gemini.cmd')
    if (fs.existsSync(geminiCmd)) {
      console.log('Found Gemini at (portable):', geminiCmd)
      return geminiCmd
    }
  }

  // Then check for gemini.cmd in system npm paths
  const additionalPaths = getAdditionalPaths()
  for (const dir of additionalPaths) {
    const geminiCmd = path.join(dir, 'gemini.cmd')
    if (fs.existsSync(geminiCmd)) {
