/**
 * Authentication Rate Limiting Module
 *
 * Provides rate limiting for failed authentication attempts.
 */

import type { RateLimitEntry } from './types.js'

// Constants
const RATE_LIMIT_MAX_ATTEMPTS = 5
const RATE_LIMIT_WINDOW_MS = 15 * 60 * 1000 // 15 minutes
const RATE_LIMIT_BLOCK_DURATION_MS = 15 * 60 * 1000 // 15 minutes

const rateLimitStore = new Map<string, RateLimitEntry>()

/**
 * Check if an IP is rate limited
 * Returns { allowed: boolean, retryAfter?: number }
 */
export function checkRateLimit(ip: string): { allowed: boolean; retryAfter?: number } {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    return { allowed: true }
  }

  // Check if currently blocked
  if (entry.blockedUntil && entry.blockedUntil > now) {
    return {
      allowed: false,
      retryAfter: Math.ceil((entry.blockedUntil - now) / 1000)
    }
  }

  // Block expired or window expired — reset so user gets fresh attempts
  if ((entry.blockedUntil && entry.blockedUntil <= now) || now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.delete(ip)
    return { allowed: true }
  }

  return { allowed: true }
}

/**
 * Record a failed authentication attempt for an IP
 * Returns true if the IP is now blocked
 */
export function recordFailedAuth(ip: string): boolean {
  const now = Date.now()
  const entry = rateLimitStore.get(ip)

  if (!entry) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Reset if window has expired
  if (now - entry.lastAttempt > RATE_LIMIT_WINDOW_MS) {
    rateLimitStore.set(ip, {
      attempts: 1,
      lastAttempt: now,
      blockedUntil: null
    })
    return false
  }

  // Increment attempts
  entry.attempts++
  entry.lastAttempt = now

  // Block if too many attempts
  if (entry.attempts >= RATE_LIMIT_MAX_ATTEMPTS) {
    entry.blockedUntil = now + RATE_LIMIT_BLOCK_DURATION_MS
    return true
  }

  return false
}

/**
 * Clear rate limit for an IP (call on successful auth)
 */
export function clearRateLimit(ip: string): void {
  rateLimitStore.delete(ip)
}

/**
 * Get rate limit status for debugging
 */
export function getRateLimitStatus(ip: string): RateLimitEntry | null {
  return rateLimitStore.get(ip) || null
}

export const authRateLimitConfig = {
  RATE_LIMIT_MAX_ATTEMPTS,
  RATE_LIMIT_WINDOW_MS,
  RATE_LIMIT_BLOCK_DURATION_MS
} as const

/**
 * WebSocket Manager - WebSocket handling
 */

import { WebSocket, WebSocketServer } from 'ws'
import { Server } from 'http'
import { log } from './utils'
import { PendingFile } from './types'

export interface WebSocketManagerDeps {
  getToken: () => string
  getPtyManager: () => any
  getPort: () => number
  getTerminalSubscriptions: () => Map<string, Set<WebSocket>>
  getPtyStreams: () => Map<string, Set<WebSocket>>
  getPtyDataBuffer: () => Map<string, string[]>
  getConnectedClients: () => Set<WebSocket>
  getPendingFiles: () => Map<string, PendingFile>
}

export function setupWebSocket(server: Server, deps: WebSocketManagerDeps): WebSocketServer {
  const wss = new WebSocketServer({ noServer: true })

  // Handle upgrade requests manually to support multiple paths
  server.on('upgrade', (req, socket, head) => {
    const url = new URL(req.url || '', `http://localhost:${deps.getPort()}`)
    const pathname = url.pathname

    // Get token from Sec-WebSocket-Protocol header (preferred) or query string (fallback)
    const protocolHeader = req.headers['sec-websocket-protocol'] as string | undefined
    const protocols = protocolHeader?.split(',').map(p => p.trim()) || []
    const tokenFromProtocol = protocols.find(p => p.startsWith('token-'))?.slice(6)
    const tokenFromQuery = url.searchParams.get('token')
    const token = tokenFromProtocol || tokenFromQuery

    log('WebSocket upgrade request', {
      url: req.url,
      pathname,
      hasProtocolToken: !!tokenFromProtocol,
      hasQueryToken: !!tokenFromQuery,
      headers: {
        host: req.headers.host,
        origin: req.headers.origin,
        upgrade: req.headers.upgrade
      }
    })

    // Validate token for all WebSocket connections
    if (token !== deps.getToken()) {
      log('WebSocket auth failed', { providedToken: token?.slice(0, 8) })
      socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n')
      socket.destroy()
      return
    }

    // Handle PTY stream WebSocket: /api/pty/:id/stream
    const ptyStreamMatch = pathname.match(/^\/api\/pty\/([^/]+)\/stream$/)
    if (ptyStreamMatch) {
      const ptyId = ptyStreamMatch[1]
      handlePtyStreamUpgrade(req, socket, head, ptyId, deps)
      return
    }

    // Handle main WebSocket path: /ws
    if (pathname === '/ws') {
      wss.handleUpgrade(req, socket, head, (ws) => {
        wss.emit('connection', ws, req)
      })
      return
    }

    // Unknown WebSocket path
    log('Unknown WebSocket path', { pathname })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
  })

  wss.on('connection', (ws: WebSocket, _req) => {
    log('WebSocket client connected (main)')

    deps.getConnectedClients().add(ws)

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())
        handleWebSocketMessage(ws, msg, deps)
      } catch (e) {
        log('Invalid WebSocket message', { error: String(e) })
      }
    })

    ws.on('close', () => {
      deps.getConnectedClients().delete(ws)

      deps.getTerminalSubscriptions().forEach((subscribers, ptyId) => {
        subscribers.delete(ws)
        if (subscribers.size === 0) {
          deps.getTerminalSubscriptions().delete(ptyId)
        }
      })
      log('WebSocket client disconnected (main)')
    })

    // Send welcome message
    ws.send(JSON.stringify({ type: 'connected', timestamp: Date.now() }))

    // Send any pending files to new client
    sendPendingFilesToClient(ws, deps.getPendingFiles())
  })

  return wss
}

function handlePtyStreamUpgrade(
  req: any,
  socket: any,
  head: any,
  ptyId: string,
  deps: WebSocketManagerDeps
): void {
  const ptyManager = deps.getPtyManager()
  if (!ptyManager || !ptyManager.getProcess(ptyId)) {
    log('PTY stream upgrade failed - PTY not found', { ptyId })
    socket.write('HTTP/1.1 404 Not Found\r\n\r\n')
    socket.destroy()
    return
  }

  const streamWss = new WebSocketServer({ noServer: true })

  streamWss.handleUpgrade(req, socket, head, (ws) => {
    log('PTY stream connected', { ptyId })

    const ptyStreams = deps.getPtyStreams()
    if (!ptyStreams.has(ptyId)) {
      ptyStreams.set(ptyId, new Set())
    }
    ptyStreams.get(ptyId)!.add(ws)

    ws.send(JSON.stringify({ type: 'connected', ptyId }))

    // Flush any buffered data
    flushPtyBuffer(ptyId, ws, deps.getPtyDataBuffer())

    ws.on('message', (message: Buffer) => {
      try {
        const msg = JSON.parse(message.toString())

        switch (msg.type) {
          case 'input':
            if (msg.data && ptyManager) {
              ptyManager.write(ptyId, msg.data)
            }
            break

          case 'resize':
            if (msg.cols && msg.rows && ptyManager) {
              ptyManager.resize(ptyId, msg.cols, msg.rows)
            }
            break

          case 'ping':
            ws.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
            break

          default:
            log('Unknown PTY stream message type', { type: msg.type, ptyId })
        }
      } catch (e) {
        log('Invalid PTY stream message', { error: String(e), ptyId })
      }
    })

    ws.on('close', () => {
      log('PTY stream disconnected', { ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
      if (ptyStreams.get(ptyId)?.size === 0) {
        ptyStreams.delete(ptyId)
      }
    })

    ws.on('error', (err) => {
      log('PTY stream error', { error: String(err), ptyId })
      ptyStreams.get(ptyId)?.delete(ws)
    })
  })
}

function handleWebSocketMessage(ws: WebSocket, msg: any, deps: WebSocketManagerDeps): void {
  const ptyManager = deps.getPtyManager()
  const terminalSubscriptions = deps.getTerminalSubscriptions()

  switch (msg.type) {
    case 'subscribe':
      if (msg.ptyId) {
        if (!terminalSubscriptions.has(msg.ptyId)) {
          terminalSubscriptions.set(msg.ptyId, new Set())
        }
        terminalSubscriptions.get(msg.ptyId)!.add(ws)
        ws.send(JSON.stringify({ type: 'subscribed', ptyId: msg.ptyId }))
      }
      break

    case 'unsubscribe':
      if (msg.ptyId) {
        terminalSubscriptions.get(msg.ptyId)?.delete(ws)
      }
      break

    case 'write':
      if (msg.ptyId && msg.data && ptyManager) {
        ptyManager.write(msg.ptyId, msg.data)
      }
      break

    case 'resize':
      if (msg.ptyId && msg.cols && msg.rows && ptyManager) {
        ptyManager.resize(msg.ptyId, msg.cols, msg.rows)
      }
      break

    case 'ping':
      ws.send(JSON.stringify({ type: 'pong', timestamp: Date.now() }))
      break
  }
}

function flushPtyBuffer(ptyId: string, ws: WebSocket, ptyDataBuffer: Map<string, string[]>): void {
  const buffer = ptyDataBuffer.get(ptyId)
  if (!buffer || buffer.length === 0) return

  buffer.forEach(data => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify({ type: 'data', data }))
    }
  })

  ptyDataBuffer.delete(ptyId)
}

function sendPendingFilesToClient(ws: WebSocket, pendingFiles: Map<string, PendingFile>): void {
  const now = Date.now()
  // Clean up expired files first
  for (const [fileId, file] of pendingFiles) {
    if (file.expiresAt < now) {
      pendingFiles.delete(fileId)
    }
  }

  const files = Array.from(pendingFiles.values()).map(f => ({
    id: f.id,
    name: f.name,
    size: f.size,
    mimeType: f.mimeType,
    message: f.message
  }))

  if (files.length > 0) {
    ws.send(JSON.stringify({ type: 'files:pending', files }))
  }
}

export function broadcastTerminalData(
  ptyId: string,
  data: string,
  terminalSubscriptions: Map<string, Set<WebSocket>>
): void {
  const subscribers = terminalSubscriptions.get(ptyId)
  if (!subscribers) return

  const message = JSON.stringify({
    type: 'terminal-data',
    ptyId,
    data
  })

  subscribers.forEach(ws => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message)
    }
  })
}

export function broadcastPtyData(
  ptyId: string,
  data: string,
  ptyStreams: Map<string, Set<WebSocket>>,
  ptyDataBuffer: Map<string, string[]>
): void {
  const streams = ptyStreams.get(ptyId)

  // If no streams connected, buffer the data
  if (!streams || streams.size === 0) {
    if (!ptyDataBuffer.has(ptyId)) {
      ptyDataBuffer.set(ptyId, [])
    }
    const buffer = ptyDataBuffer.get(ptyId)!
    buffer.push(data)
    // Limit buffer size
    if (buffer.length > 1000) {
      buffer.shift()
    }
    return
  }

  const message = JSON.stringify({
    type: 'data',
    data
  })

  streams.forEach(ws => {
    if (ws.readyState === WebSocket.OPEN) {
      ws.send(message)
    }
  })
}

export function broadcastPtyExit(
  ptyId: string,
  code: number,
  ptyStreams: Map<string, Set<WebSocket>>,
  terminalSubscriptions?: Map<string, Set<WebSocket>>,
  ptyDataBuffer?: Map<string, string[]>
): void {
  const streams = ptyStreams.get(ptyId)
  if (streams && streams.size > 0) {
    const message = JSON.stringify({
      type: 'exit',
      code
    })

    streams.forEach(ws => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(message)
        ws.close(1000, 'PTY exited')
      }
    })
  }

  // Clean up stale subscriptions and buffered data for this PTY
  ptyStreams.delete(ptyId)
  terminalSubscriptions?.delete(ptyId)
  ptyDataBuffer?.delete(ptyId)
}

/**
 * Kspec Adapter
 *
 * Talks to the kspec daemon HTTP API + IPC for init/check.
 * Normalizes kspec tasks into the unified TaskAdapter interface.
 */

import type {
  TaskAdapter,
  BackendStatus,
  UnifiedTask,
  CreateTaskParams,
  UpdateTaskParams,
  TaskStatus
} from './types.js'

const DAEMON_PORT = 3456
const API_BASE = `http://localhost:${DAEMON_PORT}`

function headers(cwd: string): HeadersInit {
  return {
    'Content-Type': 'application/json',
    'X-Kspec-Dir': cwd
  }
}

async function api<T>(method: string, path: string, cwd: string, body?: unknown, adapter?: KspecAdapter): Promise<T> {
  const opts: RequestInit = {
    method,
    headers: headers(cwd)
  }
  if (body) opts.body = JSON.stringify(body)
  let res: Response
  try {
    res = await fetch(`${API_BASE}${path}`, opts)
  } catch (e) {
    // Network error — daemon likely crashed, reset ensured flag on the instance
    if (adapter) adapter._daemonEnsuredFlag = false
    throw e
  }
  if (!res.ok) {
    const text = await res.text()
    throw new Error(text || `HTTP ${res.status}`)
  }
  return res.json()
}

function normalizeStatus(status: string): TaskStatus {
  switch (status) {
    case 'in_progress': return 'in_progress'
    case 'completed':
    case 'cancelled':
      return 'closed'
    case 'pending':
    case 'blocked':
    case 'pending_review':
    case 'needs_work':
    default:
      return 'open'
  }
}

function toUnified(raw: Record<string, unknown>): UnifiedTask {
  const tags = Array.isArray(raw.tags) ? raw.tags.map(String) : undefined
  // kspec uses _ulid as primary ID and slugs[] for human-friendly refs
  const slugs = Array.isArray(raw.slugs) ? raw.slugs : []
  // Use slug if available, otherwise full ULID (needed for API calls)
  const id = slugs.length > 0 ? String(slugs[0]) : String(raw._ulid ?? raw.slug ?? raw.id ?? '')
  return {
    id,
    // Short display ID for the UI — slug or first 8 chars of ULID
    displayId: slugs.length > 0 ? String(slugs[0]) : (id.length > 12 ? id.slice(0, 8) : id),
    title: String(raw.title ?? ''),
    status: normalizeStatus(String(raw.status ?? 'pending')),
    priority: typeof raw.priority === 'number' ? raw.priority : undefined,
    type: typeof raw.type === 'string' ? raw.type : undefined,
    description: typeof raw.description === 'string' ? raw.description : undefined,
    created_at: typeof raw.created_at === 'string' ? raw.created_at : undefined,
    updated_at: typeof raw.updated_at === 'string' ? raw.updated_at : undefined,
    tags,
    automation: typeof raw.automation === 'string' ? raw.automation as UnifiedTask['automation'] : undefined,
    _backend: 'kspec'
  }
}

export class KspecAdapter implements TaskAdapter {
  readonly kind = 'kspec' as const

  // Per-instance daemon state (avoids cross-instance interference from module-level globals)
  _daemonEnsuredFlag = true
  private _daemonEnsuredForCwd: string | null = null

  private async ensureDaemon(cwd: string): Promise<boolean> {
    // Reset flag when switching projects so we re-verify daemon for new cwd
    if (this._daemonEnsuredForCwd !== null && this._daemonEnsuredForCwd !== cwd) {
      this._daemonEnsuredFlag = false
    }

    // Quick health check first
    try {
      const res = await fetch(`${API_BASE}/api/health`)
      if (res.ok) { this._daemonEnsuredFlag = true; this._daemonEnsuredForCwd = cwd; return true }
    } catch { /* daemon not running */ }

    // Start daemon via IPC (always attempt if health check failed)
    const result = await window.electronAPI?.kspecEnsureDaemon?.(cwd)
    if (result?.success) { this._daemonEnsuredFlag = true; this._daemonEnsuredForCwd = cwd; return true }
    return false
  }

  async check(cwd: string): Promise<BackendStatus> {
    // Check if .kspec/ exists via IPC (filesystem check)
    const hasKspec = await window.electronAPI?.kspecCheck?.(cwd)
    if (!hasKspec?.exists) {
      return { kind: 'kspec', installed: true, initialized: false }
    }

    // Try to ensure daemon is running
    await this.ensureDaemon(cwd)
    return { kind: 'kspec', installed: true, initialized: true }
  }

  async init(cwd: string): Promise<{ success: boolean; error?: string }> {
    const result = await window.electronAPI?.kspecInit?.(cwd)
    return { success: !!result?.success, error: result?.error }
  }

  async list(cwd: string): Promise<UnifiedTask[]> {
    try {
      const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd, undefined, this)
      return (data.items ?? []).map(toUnified)
    } catch {
      // Daemon might not be running — try to start it and retry once
      const started = await this.ensureDaemon(cwd)
      if (started) {
        try {
          const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd, undefined, this)
          return (data.items ?? []).map(toUnified)
        } catch { /* still failed */ }
      }
      return []
    }
  }

  async show(cwd: string, taskId: string): Promise<UnifiedTask | null> {
    try {
      const data = await api<Record<string, unknown>>('GET', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, undefined, this)
      return toUnified(data)
    } catch {
      return null
    }
  }

  async create(cwd: string, params: CreateTaskParams): Promise<{ success: boolean; error?: string }> {
    try {
      await api('POST', '/api/tasks', cwd, {
        title: params.title,
        description: params.description,
        priority: params.priority,
        type: params.type,
        tags: params.tags?.split(',').map(t => t.trim()).filter(Boolean),
        automation: params.automation || undefined
      }, this)
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  }

  async start(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
    try {
      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/start`, cwd, undefined, this)
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  }

  async complete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
    try {
      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/complete`, cwd, undefined, this)
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  }

  async delete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
    try {
      await api('DELETE', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, undefined, this)
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  }

  async update(cwd: string, taskId: string, params: UpdateTaskParams): Promise<{ success: boolean; error?: string }> {
    try {
      // Map unified status names back to kspec native status names
      const body = { ...params }
      if (body.status === 'open') body.status = 'pending' as TaskStatus
      if (body.status === 'closed') body.status = 'completed' as TaskStatus
      await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, body, this)
      return { success: true }
    } catch (e) {
      return { success: false, error: String(e) }
    }
  }

  async cycleStatus(cwd: string, taskId: string, currentStatus: TaskStatus): Promise<{ success: boolean; error?: string }> {
    switch (currentStatus) {
      case 'open': return this.start(cwd, taskId)
      case 'in_progress': return this.complete(cwd, taskId)
      default:
        // Kspec uses 'pending' internally — 'open' is only the unified status
        try {
          await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, { status: 'pending' }, this)
          return { success: true }
        } catch (e) {
          return { success: false, error: String(e) }
        }
    }
  }

  // Kspec uses WebSocket for live updates instead of file watching
  private ws: WebSocket | null = null
  private wsCallbacks: Set<(data: { cwd: string }) => void> = new Set()
  private watchedCwd: string | null = null
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null
  private reconnectDelay = 1000
  private watching = false

  watch(cwd: string): void {
    // If switching projects, close old connection first
    if (this.ws && this.watchedCwd !== cwd) {
      this.ws.close()
      this.ws = null
    }
    this.watching = true
    this.watchedCwd = cwd
    this.reconnectDelay = 1000
    this.connectWs(cwd)
  }

  private connectWs(cwd: string): void {
    if (this.ws) return
    try {
      this.ws = new WebSocket(`ws://localhost:${DAEMON_PORT}/ws?project=${encodeURIComponent(cwd)}`)
      this.ws.onmessage = (event) => {
        try {
          const msg = JSON.parse(event.data)
          if (msg.event === 'tasks:updates' || msg.event === 'task_updated') {
            this.wsCallbacks.forEach(cb => cb({ cwd }))
          }
        } catch { /* ignore parse errors */ }
      }
      this.ws.onopen = () => {
        this.reconnectDelay = 1000 // Reset backoff on successful connection
      }
      this.ws.onclose = () => {
        this.ws = null
        // Auto-reconnect with exponential backoff (cap at 30s)
        if (this.watching && this.watchedCwd === cwd) {
          this.reconnectTimer = setTimeout(() => this.connectWs(cwd), this.reconnectDelay)
          this.reconnectDelay = Math.min(this.reconnectDelay * 2, 30000)
        }
      }
      this.ws.onerror = () => {
        // onclose will fire after onerror, triggering reconnect
      }
    } catch { /* daemon not running — reconnect will retry */ }
  }

  unwatch(_cwd: string): void {
    this.watching = false
    this.watchedCwd = null
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer)
      this.reconnectTimer = null
    }
    this.ws?.close()
    this.ws = null
  }

  onTasksChanged(callback: (data: { cwd: string }) => void): () => void {
    this.wsCallbacks.add(callback)
    return () => { this.wsCallbacks.delete(callback) }
  }
}

