 77→    description: typeof raw.description === 'string' ? raw.description : undefined,
 78→    created_at: typeof raw.created_at === 'string' ? raw.created_at : undefined,
 79→    updated_at: typeof raw.updated_at === 'string' ? raw.updated_at : undefined,
