111→  async check(cwd: string): Promise<BackendStatus> {
112→    // Check if .kspec/ exists via IPC (filesystem check)
113→    const hasKspec = await window.electronAPI?.kspecCheck?.(cwd)
114→    if (!hasKspec?.exists) {
115→      return { kind: 'kspec', installed: true, initialized: false }
116→    }
117→
118→    // Try to ensure daemon is running
119→    await this.ensureDaemon(cwd)
120→    return { kind: 'kspec', installed: true, initialized: true }
121→  }
122→
123→  async init(cwd: string): Promise<{ success: boolean; error?: string }> {
124→    const result = await window.electronAPI?.kspecInit?.(cwd)
125→    return { success: !!result?.success, error: result?.error }
126→  }
127→
128→  async list(cwd: string): Promise<UnifiedTask[]> {
129→    try {
130→      const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd, undefined, this)
131→      return (data.items ?? []).map(toUnified)
132→    } catch {
133→      // Daemon might not be running — try to start it and retry once
134→      const started = await this.ensureDaemon(cwd)
135→      if (started) {
136→        try {
137→          const data = await api<{ items: Record<string, unknown>[] }>('GET', '/api/tasks', cwd, undefined, this)
138→          return (data.items ?? []).map(toUnified)
139→        } catch { /* still failed */ }
140→      }
141→      return []
142→    }
143→  }
144→
145→  async show(cwd: string, taskId: string): Promise<UnifiedTask | null> {
146→    try {
147→      const data = await api<Record<string, unknown>>('GET', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, undefined, this)
148→      return toUnified(data)
149→    } catch {
150→      return null
151→    }
152→  }
153→
154→  async create(cwd: string, params: CreateTaskParams): Promise<{ success: boolean; error?: string }> {
155→    try {
156→      await api('POST', '/api/tasks', cwd, {
157→        title: params.title,
158→        description: params.description,
159→        priority: params.priority,
160→        type: params.type,
161→        tags: params.tags?.split(',').map(t => t.trim()).filter(Boolean),
162→        automation: params.automation || undefined
163→      }, this)
164→      return { success: true }
165→    } catch (e) {
166→      return { success: false, error: String(e) }
167→    }
168→  }
169→
170→  async start(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
171→    try {
172→      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/start`, cwd, undefined, this)
173→      return { success: true }
174→    } catch (e) {
175→      return { success: false, error: String(e) }
176→    }
177→  }
178→
179→  async complete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
180→    try {
181→      await api('POST', `/api/tasks/${encodeURIComponent(taskId)}/complete`, cwd, undefined, this)
182→      return { success: true }
183→    } catch (e) {
184→      return { success: false, error: String(e) }
185→    }
186→  }
187→
188→  async delete(cwd: string, taskId: string): Promise<{ success: boolean; error?: string }> {
189→    try {
190→      await api('DELETE', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, undefined, this)
191→      return { success: true }
192→    } catch (e) {
193→      return { success: false, error: String(e) }
194→    }
195→  }
196→
197→  async update(cwd: string, taskId: string, params: UpdateTaskParams): Promise<{ success: boolean; error?: string }> {
198→    try {
199→      // Map unified status names back to kspec native status names
200→      const body = { ...params }
201→      if (body.status === 'open') body.status = 'pending' as TaskStatus
202→      if (body.status === 'closed') body.status = 'completed' as TaskStatus
203→      await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, body, this)
204→      return { success: true }
205→    } catch (e) {
206→      return { success: false, error: String(e) }
207→    }
208→  }
209→
210→  async cycleStatus(cwd: string, taskId: string, currentStatus: TaskStatus): Promise<{ success: boolean; error?: string }> {
211→    switch (currentStatus) {
212→      case 'open': return this.start(cwd, taskId)
213→      case 'in_progress': return this.complete(cwd, taskId)
214→      default:
215→        // Kspec uses 'pending' internally — 'open' is only the unified status
216→        try {
217→          await api('PATCH', `/api/tasks/${encodeURIComponent(taskId)}`, cwd, { status: 'pending' }, this)
218→          return { success: true }
219→        } catch (e) {
220→          return { success: false, error: String(e) }
221→        }
222→    }
223→  }
224→
225→  // Kspec uses WebSocket for live updates instead of file watching
226→  private ws: WebSocket | null = null
227→  private wsCallbacks: Set<(data: { cwd: string }) => void> = new Set()
228→  private watchedCwd: string | null = null
229→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null
230→  private reconnectDelay = 1000
231→  private watching = false
232→
233→  watch(cwd: string): void {
234→    // If switching projects, close old connection first
235→    if (this.ws && this.watchedCwd !== cwd) {
236→      this.ws.close()
237→      this.ws = null
238→    }
239→    this.watching = true
240→    this.watchedCwd = cwd
241→    this.reconnectDelay = 1000
242→    this.connectWs(cwd)
243→  }
244→
245→  private connectWs(cwd: string): void {
246→    if (this.ws) return
247→    try {
248→      this.ws = new WebSocket(`ws://localhost:${DAEMON_PORT}/ws?project=${encodeURIComponent(cwd)}`)
249→      this.ws.onmessage = (event) => {
250→        try {
251→          const msg = JSON.parse(event.data)
252→          if (msg.event === 'tasks:updates' || msg.event === 'task_updated') {
253→            this.wsCallbacks.forEach(cb => cb({ cwd }))
254→          }
255→        } catch { /* ignore parse errors */ }
256→      }
257→      this.ws.onopen = () => {
258→        this.reconnectDelay = 1000 // Reset backoff on successful connection
259→      }
260→      this.ws.onclose = () => {
261→        this.ws = null
262→        // Auto-reconnect with exponential backoff (cap at 30s)
263→        if (this.watching && this.watchedCwd === cwd) {
264→          this.reconnectTimer = setTimeout(() => this.connectWs(cwd), this.reconnectDelay)
265→          this.reconnectDelay = Math.min(this.reconnectDelay * 2, 30000)
266→        }
267→      }
268→      this.ws.onerror = () => {
269→        // onclose will fire after onerror, triggering reconnect
270→      }
271→    } catch { /* daemon not running — reconnect will retry */ }
272→  }
273→
274→  unwatch(_cwd: string): void {
275→    this.watching = false
276→    this.watchedCwd = null
277→    if (this.reconnectTimer) {
278→      clearTimeout(this.reconnectTimer)
279→      this.reconnectTimer = null
280→    }
281→    this.ws?.close()
282→    this.ws = null
283→  }
284→
285→  onTasksChanged(callback: (data: { cwd: string }) => void): () => void {
286→    this.wsCallbacks.add(callback)
287→    return () => { this.wsCallbacks.delete(callback) }
288→  }
289→}
